INSERT INTO "public"."surveys" ("id", "title", "category", "publisher_name", "publisher_logo", "image_url", "short_description", "full_description", "bullet_points", "survey_url", "start_date", "end_date", "is_active", "created_at", "access") VALUES ('4e2503d8-4756-4eff-b780-bd11b1abe59b', 'Halk Kütüphanesi Çalışma Saatleri', 'Eğitim', 'Eğitim Birimi', 'https://via.placeholder.com/100', 'https://images.unsplash.com/photo-1521587760476-6c12a4b040da?q=80&w=800', 'Sınav dönemlerinde kütüphanemizin hizmet saatlerinin düzenlenmesi hakkında.', 'Öğrencilerimizin sınav haftalarında daha verimli çalışabilmesi adına kütüphane saatlerinde esneklik yapmayı planlıyoruz. Özellikle akşam saatleri ve hafta sonu kullanımı ile ilgili taleplerinizi bekliyoruz.', '["Hafta içi 22:00''ye kadar açık olsun","Hafta sonu tam gün hizmet verilsin","7/24 çalışma salonu oluşturulsun"]', 'https://bogazliyan.bel.tr/anket/kutuphane', '2023-01-04', '2023-01-09', 'true', '2026-01-04 09:59:39.054935+00', 'Herkes erişebilir'), ('ae3cd432-3677-4500-9f46-cb0b8e7f02b6', 'Park ve Bahçeler Düzenlemesi', 'Çevre', 'Boğazlıyan Belediyesi', 'https://via.placeholder.com/100', 'https://images.unsplash.com/photo-1596230529625-7ee541fb3552?q=80&w=800', 'İlçemizdeki yeşil alanların artırılması ve çocuk parklarının modernizasyonu konusundaki görüşlerinizi merak ediyoruz.', 'Boğazlıyan Belediyesi olarak daha yeşil ve yaşanabilir bir çevre için başlattığımız bu çalışmada, siz değerli vatandaşlarımızın fikirleri projemizin yönünü belirleyecektir. Lütfen anketi doldurarak geleceğimizi şekillendirmemize yardımcı olun.', '["Yeni park alanlarının belirlenmesi","Mevcut parkların ekipman yenilenmesi","Ağaçlandırma çalışmaları"]', 'https://bogazliyan.bel.tr/anket/1', '2023-10-10', '2023-10-25', 'true', '2026-01-04 09:55:50.525321+00', null), ('c7a932dc-24e7-4358-bbce-ed81d9eff48d', 'Bahar Şenliği Konser Tercihleri', 'Etkinlik', 'Kültür ve Sosyal İşler', 'https://via.placeholder.com/100', 'https://images.unsplash.com/photo-1459749411177-0473ef71607b?q=80&w=800', 'Bu yıl düzenlenecek geleneksel Bahar Şenliği''nde sahnede kimi görmek istersiniz?', 'Geleneksel Bahar Şenliğimiz için hazırlıklar başladı! Bu yılki konser programını sizlerin isteklerine göre şekillendirmek istiyoruz. Anketimizde yer alan müzik türleri ve sanatçı önerileri arasından tercihinizi yaparak festival coşkusuna ortak olun.', '["Halk Müziği Sanatçıları","Pop Müzik Konseri","Yerel Sanatçılar ve Sıra Gecesi"]', 'https://bogazliyan.bel.tr/anket/festival', '2026-01-04', '2026-01-25', 'true', '2026-01-04 09:59:39.054935+00', null), ('c9374fb8-bfc8-48a5-ba75-101fbce39a1f', 'Şehir İçi Otobüs Saatleri Düzenlemesi', 'Ulaşım', 'Ulaşım Hizmetleri', 'https://via.placeholder.com/100', 'https://images.unsplash.com/photo-1570125909232-eb263c188f7e?q=80&w=800', 'Vatandaşlarımızdan gelen talepler doğrultusunda otobüs sefer saatlerinde yapılması planlanan değişiklikler.', 'Kış saati uygulaması ve okul giriş-çıkış saatleri göz önüne alınarak şehir içi otobüs seferlerimizde düzenleme yapılması planlanmaktadır. Sizce en yoğun ve ihtiyaç duyulan saat aralıkları hangileridir? Görüşleriniz yeni tarifenin belirlenmesinde etkili olacaktır.', '["Sabah seferleri sıklaştırılsın (07:00-09:00)","Akşam seferleri uzatılsın (22:00 sonrası)","Hafta sonu seferleri artırılsın"]', 'https://bogazliyan.bel.tr/anket/ulasim', '2026-01-05', '2026-01-30', 'true', '2026-01-04 09:59:39.054935+00', null), ('cb096a7a-4467-45b4-8e23-6f8ec08b3e49', 'Yeni Spor Kompleksi Kursları', 'Spor', 'Gençlik ve Spor Müdürlüğü', 'https://via.placeholder.com/100', 'https://images.unsplash.com/photo-1534438327276-14e5300c3a48?q=80&w=800', 'İlçemize kazandırılan yeni spor kompleksinde açılmasını istediğiniz öncelikli kurslar nelerdir?', 'Sağlıklı bir yaşam ve gençlerimizin spora teşviki amacıyla açılan kompleksimizde faaliyete geçecek ilk kursları belirliyoruz. Hangi branşlara ilginiz daha fazla? Talebe göre eğitmen kadromuzu oluşturacağız.', '["Yüzme Kursu","Okçuluk Eğitimi","Tenis ve Badminton","Basketbol Okulu"]', 'https://bogazliyan.bel.tr/anket/spor', '2026-01-04', '2026-01-14', 'true', '2026-01-04 09:59:39.054935+00', null), ('eaeb6eec-c2ed-4de9-8923-70f1b0054282', 'Geri Dönüşüm Kutularının Yerleşimi', 'Çevre', 'Temizlik İşleri', 'https://via.placeholder.com/100', 'https://images.unsplash.com/photo-1532996122724-e3c354a0b15b?q=80&w=800', 'Daha temiz bir Boğazlıyan için geri dönüşüm noktalarının artırılması ve konumlandırılması.', 'Sıfır atık projesi kapsamında ilçemizdeki geri dönüşüm kutularının sayısını artırıyoruz. Sizce bu kutulara en çok hangi noktalarda ihtiyaç duyuluyor? Mahallenizdeki eksiklikleri bize bildirin.', '["Okul Önleri ve Parklar","Alışveriş Merkezleri Yakını","Ana Cadde ve Duraklar","Apartman Site İçleri"]', 'https://bogazliyan.bel.tr/anket/cevre', '2026-01-04', '2026-01-15', 'true', '2026-01-04 09:59:39.054935+00', null);